raw:
{
  "title_ko": "격양가",
  "translation": "해 뜨면 일하고 해 지면 쉬며\n우물 파 물 마시고 밭 갈아 밥 먹으니\n임금의 힘이 나에게 무슨 상관이랴",
  "reading": "일출이작, 일입이식\n착정이음, 경전이식\n제력어아하유재",
  "commentary": "<격양가>는 요임금 시대의 태평을 상징하는 고대 노래로 전해진다. 해가 뜨면 일하고 해가 지면 쉬며, 우물을 파 물을 마시고 밭을 갈아 먹는 삶을 가장 단순한 말로 그린다. 마지막 구절의 \"임금의 힘이 나와 무슨 상관이 있겠는가\"라는 반문은 통치가 거칠게 드러나지 않아도 백성이 편안히 산다는 이상 정치를 뜻한다. 후대에는 무위이치와 자족하는 민생의 표상으로 자주 인용된 작품이다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "擊壤",
      "meaning": "나무 막대기를 던져 땅 위의 목표물을 맞히는 놀이, 또는 풍요로움에 기뻐하며 땅을 치는 것"
    },
    {
      "word": "帝力",
      "meaning": "임금의 권력이나 통치력"
    },
    {
      "word": "何有",
      "meaning": "무엇이 있겠는가, 즉 아무런 상관이 없음을 뜻함"
    }
  ]
}

{
  "title_ko": "강구요",
  "translation": "우리 뭇 백성을 살아가게 하심은\n그대의 지극한 법도 아님이 없네\n아는 것 없고 깨달은 것 없어도\n임금님의 법도를 절로 따르나니",
  "reading": "입아증민\n막비이극\n불식부지\n순제지칙",
  "commentary": "<강구요>는 요임금의 덕치 아래 백성이 자연스럽게 살아간다는 뜻을 담은 전설적 노래이다. 백성을 길러내는 기준이 모두 임금의 법도에서 나왔지만, 정작 백성은 그것을 억지 규율로 느끼지 않는다는 점이 핵심이다. \"알지도 못하고 깨닫지도 못한 채 따르게 된다\"는 대목은 교화가 생활 속에 스며든 상태를 보여준다. 고대 중국이 꿈꾼 태평성대와 무위이치의 정치관을 압축한 짧은 노래라 할 수 있다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "蒸民",
      "meaning": "수많은 백성 또는 뭇 백성"
    },
    {
      "word": "爾",
      "meaning": "너 혹은 당신. 여기서는 노래의 대상인 요임금을 지칭함"
    },
    {
      "word": "極",
      "meaning": "지극한 표준이나 도리"
    },
    {
      "word": "則",
      "meaning": "법칙이나 준칙"
    }
  ]
}

{
  "title_ko": "이기씨납사",
  "translation": "흙은 그 본래 자리로 돌아가고\n물은 그 골짜기로 돌아가라.\n벌레들은 준동하지 말고\n풀과 나무는 그 못으로 돌아가라.",
  "reading": "토반기댁 수귀기학\n곤충무작 초목귀기택",
  "commentary": "<이기씨납사>는 한 해 농사를 마친 뒤 지내는 납제에서 불린 축원문으로 알려진다. 흙과 물, 벌레와 초목이 모두 제자리로 돌아가 인간의 삶을 해치지 않기를 바라는 내용이 짧고 단호하게 이어진다. 자연을 정복의 대상으로 보기보다 질서를 바로 세워 함께 살아가려는 농경 사회의 감각이 뚜렷하다. 현존 전승 가운데 매우 이른 시기의 제의 언어를 보여 주어 고대 생활 의식과 세계관을 엿보게 하는 작품이다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "이기씨",
      "meaning": "고대 전설상의 제왕인 신농씨 또는 요임금을 일컫는 칭호"
    },
    {
      "word": "납",
      "meaning": "연말에 만물의 신에게 한 해 농사의 성공을 감사하며 드리는 제사"
    },
    {
      "word": "반기댁",
      "meaning": "자신의 본래 자리(거처)로 되돌아감"
    },
    {
      "word": "무작",
      "meaning": "일어나지 마라, 또는 해를 끼치지 마라"
    },
    {
      "word": "택",
      "meaning": "늪이나 못. 여기서는 야생 식물이 자라는 원래의 서식처를 의미"
    }
  ]
}

{
  "title_ko": "요계",
  "translation": "벌벌 떨며 두려워하고, 날마다 더욱 조심하라.\n사람은 산에 걸려 넘어지지 않고, 작은 흙더미에 걸려 넘어지느니라.",
  "reading": "전전율율 일근일일\n인막질어산 이질어질",
  "commentary": "<요계>는 요임금의 경계의 말로 전해지는 짧은 금언이다. 큰 산에서는 잘 넘어지지 않지만 작은 흙더미에서 오히려 발이 걸린다는 비유가 중심 뜻을 이룬다. 눈에 띄는 큰 위험보다 사소한 방심과 익숙함이 더 큰 화를 부른다는 교훈을 매우 선명하게 전한다. 뒤의 여러 유가 문헌에서 군자의 수양과 정치의 조심스러움을 말할 때 즐겨 끌어온 구절이라, 짧지만 영향력은 매우 컸다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "戰戰慄慄",
      "meaning": "몹시 두려워하며 벌벌 떨고 조심함"
    },
    {
      "word": "躓",
      "meaning": "발이 걸려 넘어짐"
    },
    {
      "word": "垤",
      "meaning": "개미둑 또는 작은 흙더미"
    }
  ]
}

{
  "title_ko": "경운가",
  "translation": "상서로운 구름 찬란하구나, 얽히어 유유히 흐르네.\n해와 달의 빛 영롱하니, 날이 가고 또 날이 밝아오네.",
  "reading": "경운란혜, 규만만혜.\n일월광화, 단부단혜.",
  "commentary": "<경운가>는 순임금이 선양의 자리에서 불렀다고 전하는 상서로운 노래이다. 찬란한 구름과 해와 달의 빛을 통해 태평성대와 천명의 이어짐을 기리는 분위기가 장중하게 드러난다. 구름의 펼쳐짐과 날의 거듭남은 새 시대가 밝아오는 징조이자 덕 있는 통치의 지속을 상징한다. 그래서 이 작품은 단순한 자연 찬미가 아니라 왕조의 화합, 선양의 정당성, 성왕의 정치 이상을 함께 담은 정치적 상징시로 읽힌다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "卿雲",
      "meaning": "상서로운 구름. 태평성대의 징조로 여겨짐"
    },
    {
      "word": "糺",
      "meaning": "얽히다. 구름이 서로 뒤섞여 있는 모습"
    },
    {
      "word": "縵縵",
      "meaning": "구름이 느릿느릿하게 퍼져 나가는 모양"
    },
    {
      "word": "光華",
      "meaning": "빛나고 화려함. 찬란한 영광의 빛"
    },
    {
      "word": "旦復旦",
      "meaning": "날마다 새로움. 아침이 지나고 다시 아침이 옴"
    }
  ]
}

{
  "title_ko": "팔백가",
  "translation": "밝고 밝은 저 하늘이여, 찬란하게 별들이 벌여 있도다.\n해와 달의 빛나는 정화가, 한 사람에게 넓게 퍼지누나.",
  "reading": "명명상천, 난연성진.\n일월광화, 홍어일인.",
  "commentary": "<팔백가>는 밝은 하늘과 별자리, 해와 달의 광휘를 한 사람의 성스러운 통치에 모아 놓는 노래이다. 우주 질서가 한 임금에게 집중되는 듯한 표현을 통해 성왕의 덕을 찬양하는 제의적 성격이 강하다. 특히 천문과 군주의 결합은 고대 정치에서 하늘의 명과 인간의 통치가 분리되지 않았음을 보여 준다. 짧은 형식이지만 천상 질서와 왕권의 정당성을 결박하는 상고 시대 노래의 성격이 선명하게 남아 있다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "爛然",
      "meaning": "빛이 아주 눈부시고 찬란한 모양"
    },
    {
      "word": "星陳",
      "meaning": "별들이 하늘에 차례대로 벌여 있는 것. 여기서 陳은 늘어놓다는 뜻"
    },
    {
      "word": "光華",
      "meaning": "빛나고 화려함. 또는 해와 달의 빛나는 정화"
    },
    {
      "word": "一人",
      "meaning": "천자를 일컫는 말. 여기서는 순 임금을 가리킴"
    }
  ]
}

{
  "title_ko": "제재가",
  "translation": "해와 달은 일정한 법도가 있고, 별들은 제 길을 운행하도다.\n네 계절은 법도를 따르고, 온 백성은 진실로 정성스럽도다.\n아, 내 음악을 논함에 있어, 하늘의 신령함과 짝을 이루도다.\n어질고 착한 이에게 자리를 물려주니, 따르지 않는 이가 아무도 없도다.\n둥둥 북을 울리고, 훨훨 위엄 있게 춤을 추도다.\n나의 정화가 이미 다하였으니, 옷자락 걷어 올리고 이제 떠나가노라.",
  "reading": "일월유상, 성신유행.\n사시종경, 만성윤성.\n오여론악, 배천지령.\n천어현선, 막불함청.\n창호고지, 헌호무지.\n정화이갈, 견상거지.",
  "commentary": "<제재가>는 해와 달, 별과 사계절의 운행에서 시작해 임금의 음악과 교화, 그리고 떠남의 장면까지 아우르는 비교적 긴 고대 노래이다. 앞부분은 우주 질서와 백성의 성실함을 말하고, 중간은 어진 이를 등용해 모두가 기꺼이 따르는 정치의 이상을 드러낸다. 끝의 북과 춤, 그리고 옷자락을 걷어 떠나는 장면은 의례가 끝난 뒤의 여운까지 남긴다. 천도, 예악, 인재 등용이 하나의 질서로 연결된다는 점이 이 작품의 핵심이다. 또 이 노래들은 후대 사서와 유가 전통 속에서 성왕의 덕치, 선양, 태평의 증거처럼 반복 인용되었다. 문학 작품이면서 동시에 정치적 교과서 구실을 했다는 점에서 상고 가요의 기능을 잘 보여 준다. 짧은 형식 안에 당시의 가치관과 언어 감각을 응축해 보여 준다는 점에서도 자료적 의미가 크다.",
  "notes": [
    {
      "word": "允誠",
      "meaning": "진실로 정성스러움"
    },
    {
      "word": "鼚",
      "meaning": "북을 치는 소리"
    },
    {
      "word": "軒",
      "meaning": "춤추는 모습이 높고 위엄 있음"
    },
    {
      "word": "菁華",
      "meaning": "사물의 정수. 여기서는 임금으로서의 덕치나 기력을 의미함"
    },
    {
      "word": "褰裳",
      "meaning": "하의를 걷어 올림. 자리를 물러나 떠나가는 모습"
    }
  ]
}

{
  "title_ko": "남풍가",
  "translation": "남풍의 훈훈함이여, 우리 백성의 원망을 풀어줄 수 있도다!\n남풍의 때맞춤이여, 우리 백성의 재물을 불려줄 수 있도다!",
  "reading": "남풍지지훈혜, 가이해오민지온혜!\n남풍지지시혜, 가이부오민지재혜!",
